import{_ as a,c as l,o as s,a1 as t}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"兼容性: Claude Code 技能 | opencode-agent-skills","description":"学习 OpenCode Agent Skills 如何兼容 Claude Code 技能和插件系统。掌握工具映射机制、技能发现优先级，复用 Claude 技能生态。","frontmatter":{"title":"兼容性: Claude Code 技能 | opencode-agent-skills","sidebarTitle":"复用 Claude 技能","subtitle":"Claude Code 技能兼容性","description":"学习 OpenCode Agent Skills 如何兼容 Claude Code 技能和插件系统。掌握工具映射机制、技能发现优先级，复用 Claude 技能生态。","tags":["兼容性","Claude Code","技能复用"],"prerequisite":["start-what-is-opencode-agent-skills","platforms-skill-discovery-mechanism"],"order":1},"headers":[],"relativePath":"zh/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md","filePath":"zh/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md"}'),d={name:"zh/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md"};function o(i,e,n,r,c,p){return s(),l("div",null,[...e[0]||(e[0]=[t(`<h1 id="claude-code-技能兼容性" tabindex="-1">Claude Code 技能兼容性 <a class="header-anchor" href="#claude-code-技能兼容性" aria-label="Permalink to &quot;Claude Code 技能兼容性&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>理解插件如何自动兼容 Claude Code 技能格式</li><li>掌握工具映射机制，让 Claude 技能在 OpenCode 中正确工作</li><li>了解技能发现的完整优先级规则</li><li>复用 Claude 插件市场中的现有技能，无需重新编写</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>你已经有一些 Claude Code 的技能，或者想用 Claude 插件市场上的技能，但这些技能都是为 Claude Code 编写的。直接在 OpenCode 中使用会遇到问题：</p><ul><li>Claude 技能中的工具调用（如 <code>TodoWrite</code>、<code>Task</code>）在 OpenCode 中不存在</li><li>不清楚如何让 OpenCode 找到已安装的 Claude 插件技能</li><li>担心技能格式不兼容，需要重写所有内容</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>OpenCode Agent Skills 插件通过<strong>三层兼容机制</strong>，让你无需修改即可使用 Claude Code 技能：</p><ol><li><strong>自动发现</strong> - 从 Claude Code 的标准目录（<code>.claude/skills/</code>、<code>~/.claude/plugins/</code>）扫描技能</li><li><strong>工具映射</strong> - 加载技能时自动注入工具映射指南，将 Claude 工具名转为 OpenCode 工具名</li><li><strong>格式支持</strong> - 同时支持 Claude 插件的 v1 和 v2 两种安装格式</li></ol><div class="info custom-block"><p class="custom-block-title">关键概念</p><p><strong>Claude Code 技能格式</strong> - Anthropic 定义的技能规范，使用 <code>SKILL.md</code> 文件描述技能，包含 YAML frontmatter（元数据）和 Markdown 内容（指令）。</p></div><h3 id="工具映射原理" tabindex="-1">工具映射原理 <a class="header-anchor" href="#工具映射原理" aria-label="Permalink to &quot;工具映射原理&quot;">​</a></h3><p>当插件检测到加载的是 Claude Code 编写的技能时，会自动注入工具映射指南：</p><table tabindex="0"><thead><tr><th>Claude Code 工具</th><th>OpenCode 工具</th><th>映射规则</th></tr></thead><tbody><tr><td><code>TodoWrite/TodoRead</code></td><td><code>todowrite/todoread</code></td><td>小写</td></tr><tr><td><code>Task</code> (子代理)</td><td><code>task</code> (带 subagent_type 参数)</td><td>改用参数</td></tr><tr><td><code>Skill</code></td><td><code>use_skill</code></td><td>替换工具名</td></tr><tr><td><code>Read/Write/Edit/Bash/Glob/Grep/WebFetch</code></td><td><code>read/write/edit/bash/glob/grep/webfetch</code></td><td>小写</td></tr></tbody></table><p><strong>映射方式</strong>：插件在加载技能时，将映射指南作为 XML 注入到会话上下文中，AI 会自动按照映射调用正确的工具。</p><div class="tip custom-block"><p class="custom-block-title">为什么需要映射？</p><p>Claude Code 和 OpenCode 的工具命名风格不同。Claude 使用 PascalCase（如 <code>TodoWrite</code>），OpenCode 使用小写（如 <code>todowrite</code>）。工具映射让 AI 知道如何转换调用。</p></div><h3 id="技能发现优先级" tabindex="-1">技能发现优先级 <a class="header-anchor" href="#技能发现优先级" aria-label="Permalink to &quot;技能发现优先级&quot;">​</a></h3><p>插件按照以下顺序发现技能，<strong>第一个匹配的技能生效</strong>（同名技能不会重复）：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[技能发现流程] --&gt; B[项目级 OpenCode]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; |.opencode/skills/| C[1. project]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[项目级 Claude Code]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; |.claude/skills/| E[2. claude-project]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[用户级 OpenCode]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; |~/.config/opencode/skills/| G[3. user]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[用户级 Claude Code]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; |~/.claude/skills/| I[4. claude-user]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt; J[Claude 插件缓存]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    J --&gt; |~/.claude/plugins/cache/| K[5. claude-plugins]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    K --&gt; L[Claude 插件市场]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    L --&gt; |~/.claude/plugins/marketplaces/| M[6. claude-plugins]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#e1f5e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style E fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style G fill:#e1f5e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style I fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style K fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style M fill:#fff4e1</span></span></code></pre></div><p><strong>优先级规则</strong>：</p><ul><li>项目级技能覆盖用户级技能（方便项目定制）</li><li>OpenCode 技能优先于 Claude 技能（避免混淆）</li><li>同名技能只保留首次发现的版本</li></ul><details class="details custom-block"><summary>示例：同名技能覆盖</summary><p>假设你在两个位置都有名为 <code>git-helper</code> 的技能：</p><ul><li><code>.claude/skills/git-helper/SKILL.md</code> （Claude 版本）</li><li><code>.opencode/skills/git-helper/SKILL.md</code> （OpenCode 版本）</li></ul><p><strong>结果</strong>：OpenCode 版本生效（优先级更高）</p></details><h2 id="🎒-开始前的准备" tabindex="-1">🎒 开始前的准备 <a class="header-anchor" href="#🎒-开始前的准备" aria-label="Permalink to &quot;🎒 开始前的准备&quot;">​</a></h2><ul><li>已安装并配置 OpenCode Agent Skills 插件</li><li>了解基础技能概念（推荐先阅读<a href="./../../start/what-is-opencode-agent-skills/">什么是 OpenCode Agent Skills？</a>）</li><li>（可选）有 Claude Code 的已安装插件或技能</li></ul><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-检查-claude-技能是否被发现" tabindex="-1">第 1 步：检查 Claude 技能是否被发现 <a class="header-anchor" href="#第-1-步-检查-claude-技能是否被发现" aria-label="Permalink to &quot;第 1 步：检查 Claude 技能是否被发现&quot;">​</a></h3><p><strong>为什么</strong> 确认插件能正确扫描到你的 Claude Code 技能目录。</p><p>在 OpenCode 中调用工具：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>get_available_skills()</span></span></code></pre></div><p><strong>你应该看到</strong>：返回的技能列表中包含来自 <code>.claude/skills/</code>、<code>~/.claude/skills/</code>、<code>~/.claude/plugins/</code> 的技能，每个技能的 <code>source</code> 字段显示来源（如 <code>claude-project</code>、<code>claude-user</code>、<code>claude-plugins</code>）。</p><p><strong>检查点 ✅</strong>：确认列表中包含预期的 Claude 技能。</p><h3 id="第-2-步-加载-claude-技能" tabindex="-1">第 2 步：加载 Claude 技能 <a class="header-anchor" href="#第-2-步-加载-claude-技能" aria-label="Permalink to &quot;第 2 步：加载 Claude 技能&quot;">​</a></h3><p><strong>为什么</strong> 验证工具映射机制是否正常工作。</p><p>调用工具加载一个 Claude 技能：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>use_skill(skill=&quot;你的技能名称&quot;)</span></span></code></pre></div><p><strong>你应该看到</strong>：返回成功消息，如 <code>Skill &quot;xxx&quot; loaded.</code>。</p><p><strong>检查点 ✅</strong>：AI 现在可以使用该技能的指令。</p><h3 id="第-3-步-验证工具映射生效" tabindex="-1">第 3 步：验证工具映射生效 <a class="header-anchor" href="#第-3-步-验证工具映射生效" aria-label="Permalink to &quot;第 3 步：验证工具映射生效&quot;">​</a></h3><p><strong>为什么</strong> 确认 AI 能正确调用 OpenCode 的工具而非 Claude 的工具。</p><p>向 AI 提出一个需要该技能工具的任务，例如：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请用技能中的 todo 功能帮我创建任务列表。</span></span></code></pre></div><p><strong>你应该看到</strong>：AI 正确调用 OpenCode 的 <code>todowrite</code> 工具，而不是 Claude 的 <code>TodoWrite</code> 工具。</p><div class="tip custom-block"><p class="custom-block-title">如何验证映射生效？</p><p>查看 AI 的工具调用日志（如果启用了调试模式），你会看到它调用的是 <code>todowrite</code> 而非 <code>TodoWrite</code>。</p></div><p><strong>检查点 ✅</strong>：工具调用成功，任务完成。</p><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="_1-插件格式不匹配" tabindex="-1">1. 插件格式不匹配 <a class="header-anchor" href="#_1-插件格式不匹配" aria-label="Permalink to &quot;1. 插件格式不匹配&quot;">​</a></h3><p><strong>问题</strong>：旧版 Claude 插件使用 v1 格式，新版使用 v2 格式，导致某些技能无法被发现。</p><p><strong>原因</strong>：v1 和 v2 的 <code>installed_plugins.json</code> 结构不同。</p><p><strong>解决</strong>：插件同时支持两种格式，无需手动转换。如果仍无法发现技能，检查 <code>~/.claude/plugins/installed_plugins.json</code> 是否存在且格式正确。</p><h3 id="_2-工具映射未生效" tabindex="-1">2. 工具映射未生效 <a class="header-anchor" href="#_2-工具映射未生效" aria-label="Permalink to &quot;2. 工具映射未生效&quot;">​</a></h3><p><strong>问题</strong>：AI 仍调用 Claude 工具名，导致报错。</p><p><strong>原因</strong>：技能内容可能绕过了工具映射指南，或者使用了硬编码的工具调用。</p><p><strong>解决</strong>：</p><ul><li>确认技能是加载后使用，而非直接调用工具</li><li>如果技能中有代码示例，手动将工具名改为 OpenCode 格式</li></ul><h3 id="_3-技能命名冲突" tabindex="-1">3. 技能命名冲突 <a class="header-anchor" href="#_3-技能命名冲突" aria-label="Permalink to &quot;3. 技能命名冲突&quot;">​</a></h3><p><strong>问题</strong>：同名技能在不同位置，加载的是错误的版本。</p><p><strong>原因</strong>：技能发现优先级导致的覆盖。</p><p><strong>解决</strong>：</p><ul><li>检查技能的 <code>source</code> 字段，确认来源</li><li>使用命名空间格式明确指定来源：<code>use_skill(skill=&quot;user:skill-name&quot;)</code> 或 <code>use_skill(skill=&quot;claude-plugins:skill-name&quot;)</code></li></ul><details class="details custom-block"><summary>命名空间语法</summary><p>插件支持 <code>namespace:skill-name</code> 格式：</p><ul><li><code>project:skill-name</code> - 项目级 OpenCode 技能</li><li><code>claude-project:skill-name</code> - 项目级 Claude 技能</li><li><code>user:skill-name</code> - 用户级 OpenCode 技能</li><li><code>claude-user:skill-name</code> - 用户级 Claude 技能</li><li><code>claude-plugins:skill-name</code> - Claude 插件市场技能</li></ul></details><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>OpenCode Agent Skills 插件通过三层兼容机制，让你无缝复用 Claude Code 技能：</p><ul><li><strong>自动发现</strong> - 从 6 个位置扫描技能，覆盖项目级、用户级、插件级</li><li><strong>工具映射</strong> - 自动将 Claude 工具名转换为 OpenCode 工具名</li><li><strong>格式支持</strong> - 同时支持 v1 和 v2 两种 Claude 插件格式</li></ul><p>无需重写技能，直接安装并使用，插件会自动处理兼容性问题。</p><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../superpowers-integration/">Superpowers 工作流集成</a></strong>。</p><p>你会学到：</p><ul><li>如何启用 Superpowers 模式</li><li>Superpowers 技能的自动检测和加载</li><li>严格工作流如何提升开发效率</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>工具映射定义</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L19-L25" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>19-25</td></tr><tr><td>v1/v2 格式类型定义</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L35-L61" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>35-61</td></tr><tr><td>插件安装路径提取</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L68-L77" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>68-77</td></tr><tr><td>发现插件技能</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L82-L105" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>82-105</td></tr><tr><td>发现市场技能</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L115-L180" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>115-180</td></tr><tr><td>发现缓存技能</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L193-L253" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>193-253</td></tr><tr><td>技能发现优先级列表</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L241-L254" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>241-254</td></tr><tr><td>同名技能去重逻辑</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L256-L260" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>256-260</td></tr><tr><td>toolTranslation 导入</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L15" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>15</td></tr><tr><td>工具映射注入</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L238-L249" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>238-249</td></tr></tbody></table><p><strong>关键常量</strong>：</p><ul><li><code>toolTranslation</code>：工具映射指南 XML 字符串，在加载技能时注入到会话上下文。在 <code>src/claude.ts:19-25</code> 定义，在 <code>src/tools.ts:15</code> 导入</li></ul><p><strong>关键函数</strong>：</p><ul><li><code>getPluginInstallPaths()</code>：从 v1/v2 格式中提取插件安装路径</li><li><code>discoverSkillsFromPluginDir()</code>：扫描插件目录的 skills/ 子目录</li><li><code>discoverMarketplaceSkills()</code>：从 <code>~/.claude/plugins/marketplaces/</code> 发现技能（优先）</li><li><code>discoverPluginCacheSkills()</code>：从 <code>~/.claude/plugins/cache/</code> 发现技能（作为降级方案）</li><li><code>findFile()</code>：递归查找指定文件名（工具函数）</li></ul><p><strong>重要流程</strong>：</p><ol><li>插件初始化时调用 <code>discoverAllSkills()</code> → 遍历 6 个发现路径</li><li>发现 Claude 插件技能时调用 <code>discoverMarketplaceSkills()</code> 或 <code>discoverPluginCacheSkills()</code></li><li>加载技能时，<code>use_skill</code> 工具在 XML 内容中插入 <code>toolTranslation</code>（第 244 行）</li></ol></details>`,68)])])}const g=a(d,[["render",o]]);export{u as __pageData,g as default};
